namespace sv_b7d7d3062b0b46d38c3b76d90747aafa.Services;

/// <summary>
/// Scoped service (per-circuit in Blazor Server) that holds the currently
/// selected warehouse and notifies all subscribers when it changes.
/// Each user circuit gets its own independent instance.
/// </summary>
public class WarehouseStateService
{
    public static readonly IReadOnlyList<(string Id, string Name)> AvailableWarehouses =
    [
        ("WH-A", "Warehouse A"),
        ("WH-B", "Warehouse B"),
        ("WH-C", "Warehouse C"),
    ];

    private string _currentWarehouseId = AvailableWarehouses[0].Id;

    public string CurrentWarehouseId => _currentWarehouseId;

    public string CurrentWarehouseName =>
        AvailableWarehouses.FirstOrDefault(w => w.Id == _currentWarehouseId).Name
        ?? _currentWarehouseId;

    public event Action? OnChange;

    public void SetWarehouse(string warehouseId)
    {
        if (_currentWarehouseId == warehouseId) return;
        _currentWarehouseId = warehouseId;
        OnChange?.Invoke();
    }
}

namespace sv_b7d7d3062b0b46d38c3b76d90747aafa.Services;

/// <summary>
/// Scoped service (per-circuit) that provides low-stock alert counts and
/// broadcasts changes to all subscribed components via an event.
/// </summary>
public class InventoryAlertService
{
    private readonly Random _random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnAlertCountChanged;

    /// <summary>
    /// Simulates a database query returning low-stock item count for a warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        var count = _random.Next(0, 16); // 0–15 inclusive
        return Task.FromResult(count);
    }

    /// <summary>
    /// Polls for new alert data, caches the result, and notifies all subscribers.
    /// Called by whichever component owns the polling timer.
    /// </summary>
    public async Task RefreshAlertCountAsync(string warehouseId)
    {
        CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
        OnAlertCountChanged?.Invoke();
    }
}

