@using sv_b7d7d3062b0b46d38c3b76d90747aafa.Services
@rendermode InteractiveServer
@implements IDisposable
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService

<select class="form-select form-select-sm"
        style="width: auto; display: inline-block;"
        value="@WarehouseState.CurrentWarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseStateService.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    protected override void OnInitialized()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
    }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var newId = e.Value?.ToString() ?? "";
        WarehouseState.SetWarehouse(newId);
        // Immediately refresh alerts for the new warehouse
        await AlertService.RefreshAlertCountAsync(newId);
    }

    private void HandleWarehouseChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        WarehouseState.OnChange -= HandleWarehouseChanged;
    }
}

@using sv_b7d7d3062b0b46d38c3b76d90747aafa.Services
@rendermode InteractiveServer
@implements IDisposable
@inject InventoryAlertService AlertService

<span class="badge @BadgeClass">@AlertService.CurrentAlertCount</span>

@code {
    [Parameter]
    public string BadgeClass { get; set; } = "bg-danger";

    protected override void OnInitialized()
    {
        AlertService.OnAlertCountChanged += HandleAlertCountChanged;
    }

    private void HandleAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        AlertService.OnAlertCountChanged -= HandleAlertCountChanged;
    }
}

@page "/dashboard"
@using sv_b7d7d3062b0b46d38c3b76d90747aafa.Services
@rendermode InteractiveServer
@implements IDisposable
@inject WarehouseStateService WarehouseState
@inject InventoryAlertService AlertService

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            <AlertBadge BadgeClass="@(AlertService.CurrentAlertCount > 0 ? "bg-danger" : "bg-success")" />
        </p>
        <p class="text-muted" style="font-size: 0.85rem;">
            Polling every 10 seconds. Last check: @_lastPollTime?.ToString("T")
        </p>
    </div>
</div>

@code {
    private Timer? _pollTimer;
    private DateTime? _lastPollTime;

    protected override async Task OnInitializedAsync()
    {
        WarehouseState.OnChange += HandleWarehouseChanged;
        AlertService.OnAlertCountChanged += HandleAlertCountChanged;

        // Initial fetch
        await AlertService.RefreshAlertCountAsync(WarehouseState.CurrentWarehouseId);
        _lastPollTime = DateTime.Now;

        // Start polling every 10 seconds
        _pollTimer = new Timer(PollCallback, null, TimeSpan.FromSeconds(10), TimeSpan.FromSeconds(10));
    }

    private async void PollCallback(object? state)
    {
        await AlertService.RefreshAlertCountAsync(WarehouseState.CurrentWarehouseId);
        _lastPollTime = DateTime.Now;
        await InvokeAsync(StateHasChanged);
    }

    private void HandleWarehouseChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    private void HandleAlertCountChanged()
    {
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _pollTimer?.Dispose();
        WarehouseState.OnChange -= HandleWarehouseChanged;
        AlertService.OnAlertCountChanged -= HandleAlertCountChanged;
    }
}

